1	// cli.ts
2	import {
3	  quote,
4	  claim,
5	  insuranceSum,
6	  isKnownItemType,
7	  type Item,
8	} from "./claim-office.js";
9	
10	type QuoteStep = { op: "quote"; items: Item[] };
11	type ClaimStep = {
12	  op: "claim";
13	  policy: number;
14	  incident: { cause: string; damages: { itemType: string; amount: number }[] };
15	};
16	type Step = QuoteStep | ClaimStep;
17	
18	type Scenario = {
19	  customer: { yearsWithMHPCO: number };
20	  steps: Step[];
21	};
22	
23	type Policy = {
24	  items: Item[];
25	  remainingCap: number;
26	};
27	
28	type StepResult = { premium: number } | { payout: number; remainingCap: number };
29	
30	const CAP_MULTIPLIER = 2;
31	
32	async function readStdin(): Promise<string> {
33	  const chunks: Buffer[] = [];
34	  for await (const chunk of process.stdin) {
35	    chunks.push(chunk as Buffer);
36	  }
37	  return Buffer.concat(chunks).toString("utf8");
38	}
39	
40	function fail(message: string): never {
41	  console.error(message);
42	  process.exit(1);
43	}
44	
45	function validateItems(items: Item[]): void {
46	  for (const item of items) {
47	    if (!isKnownItemType(item.type)) {
48	      fail(`Unknown item type: ${item.type}`);
49	    }
50	  }
51	}
52	
53	function processQuote(
54	  step: QuoteStep,
55	  customerYears: number,
56	  previousContracts: number,
57	  policies: Policy[],
58	): StepResult {
59	  validateItems(step.items);
60	  const premium = quote({
61	    items: step.items,
62	    customerYears,
63	    previousContracts,
64	  });
65	  policies.push({
66	    items: step.items,
67	    remainingCap: insuranceSum(step.items) * CAP_MULTIPLIER,
68	  });
69	  return { premium };
70	}
71	
72	function countByType<T>(items: T[], getType: (item: T) => string): Map<string, number> {
73	  const counts = new Map<string, number>();
74	  for (const item of items) {
75	    const key = getType(item);
76	    counts.set(key, (counts.get(key) ?? 0) + 1);
77	  }
78	  return counts;
79	}
80	
81	function validateDamages(damages: { itemType: string }[], policyItems: Item[]): void {
82	  const damageCounts = countByType(damages, (d) => d.itemType);
83	  const policyCounts = countByType(policyItems, (i) => i.type);
84	  for (const [itemType, count] of damageCounts) {
85	    if (count > (policyCounts.get(itemType) ?? 0)) {
86	      fail(`More damages of type ${itemType} than policy covers`);
87	    }
88	  }
89	}
90	
91	function processClaim(step: ClaimStep, policies: Policy[]): StepResult {
92	  const policy = policies[step.policy];
93	  validateDamages(step.incident.damages, policy.items);
94	  const result = claim({
95	    items: policy.items,
96	    remainingCap: policy.remainingCap,
97	    damages: step.incident.damages,
98	  });
99	  policy.remainingCap = result.remainingCap;
100	  return result;
101	}
102	
103	async function main() {
104	  const raw = await readStdin();
105	  const scenario: Scenario = JSON.parse(raw);
106	
107	  const results: StepResult[] = [];
108	  const policies: Policy[] = [];
109	  let previousContracts = 0;
110	
111	  for (const step of scenario.steps) {
112	    if (step.op === "quote") {
113	      results.push(
114	        processQuote(step, scenario.customer.yearsWithMHPCO, previousContracts, policies),
115	      );
116	      previousContracts += 1;
117	    } else {
118	      results.push(processClaim(step, policies));
119	    }
120	  }
121	
122	  console.log(JSON.stringify({ results }));
123	}
124	
125	main().catch((err) => {
126	  console.error(err instanceof Error ? err.message : String(err));
127	  process.exit(1);
128	});
